/// <summary>
/// Error taxonomy with structured, actionable messages.
/// </summary>
internal class SeyfrException: UniffiException {
    SeyfrException() : base() {}
    SeyfrException(String @Message) : base(@Message) {}

    // Each variant is a nested class
    
    
    public class Io : SeyfrException {
        // Members
        public string @details;

        // Constructor
        public Io(
                string @details) : base(
                "@details" + "=" + @details) {

            this.@details = @details;
        }
    }
    
    
    public class InvalidTicket : SeyfrException {
        // Members
        public string @details;

        // Constructor
        public InvalidTicket(
                string @details) : base(
                "@details" + "=" + @details) {

            this.@details = @details;
        }
    }
    
    
    public class Network : SeyfrException {
        // Members
        public string @details;

        // Constructor
        public Network(
                string @details) : base(
                "@details" + "=" + @details) {

            this.@details = @details;
        }
    }
    
    
    public class Store : SeyfrException {
        // Members
        public string @details;

        // Constructor
        public Store(
                string @details) : base(
                "@details" + "=" + @details) {

            this.@details = @details;
        }
    }
    
    public class Cancelled : SeyfrException {
        public Cancelled() : base() {}
    }
    
    
    
    public class FileNotFound : SeyfrException {
        // Members
        public string @path;

        // Constructor
        public FileNotFound(
                string @path) : base(
                "@path" + "=" + @path) {

            this.@path = @path;
        }
    }
    
    
    public class NotADirectory : SeyfrException {
        // Members
        public string @path;

        // Constructor
        public NotADirectory(
                string @path) : base(
                "@path" + "=" + @path) {

            this.@path = @path;
        }
    }
    
    
    public class EmptyFolder : SeyfrException {
        // Members
        public string @path;

        // Constructor
        public EmptyFolder(
                string @path) : base(
                "@path" + "=" + @path) {

            this.@path = @path;
        }
    }
    
    public class Timeout : SeyfrException {
        public Timeout() : base() {}
    }
    
    
    
    public class Internal : SeyfrException {
        // Members
        public string @details;

        // Constructor
        public Internal(
                string @details) : base(
                "@details" + "=" + @details) {

            this.@details = @details;
        }
    }
    
    
    public class PathTraversal : SeyfrException {
        // Members
        public string @path;
        public string @details;

        // Constructor
        public PathTraversal(
                string @path, 
                string @details) : base(
                "@path" + "=" + @path+ ", " +
                "@details" + "=" + @details) {

            this.@path = @path;

            this.@details = @details;
        }
    }
    
    
    public class InvalidPath : SeyfrException {
        // Members
        public string @details;

        // Constructor
        public InvalidPath(
                string @details) : base(
                "@details" + "=" + @details) {

            this.@details = @details;
        }
    }
    

    
}

class FfiConverterTypeSeyfrError : FfiConverterRustBuffer<SeyfrException>, CallStatusErrorHandler<SeyfrException> {
    public static FfiConverterTypeSeyfrError INSTANCE = new FfiConverterTypeSeyfrError();

    public override SeyfrException Read(BigEndianStream stream) {
        var value = stream.ReadInt();
        switch (value) {
            case 1:
                return new SeyfrException.Io(
                    FfiConverterString.INSTANCE.Read(stream));
            case 2:
                return new SeyfrException.InvalidTicket(
                    FfiConverterString.INSTANCE.Read(stream));
            case 3:
                return new SeyfrException.Network(
                    FfiConverterString.INSTANCE.Read(stream));
            case 4:
                return new SeyfrException.Store(
                    FfiConverterString.INSTANCE.Read(stream));
            case 5:
                return new SeyfrException.Cancelled();
            case 6:
                return new SeyfrException.FileNotFound(
                    FfiConverterString.INSTANCE.Read(stream));
            case 7:
                return new SeyfrException.NotADirectory(
                    FfiConverterString.INSTANCE.Read(stream));
            case 8:
                return new SeyfrException.EmptyFolder(
                    FfiConverterString.INSTANCE.Read(stream));
            case 9:
                return new SeyfrException.Timeout();
            case 10:
                return new SeyfrException.Internal(
                    FfiConverterString.INSTANCE.Read(stream));
            case 11:
                return new SeyfrException.PathTraversal(
                    FfiConverterString.INSTANCE.Read(stream),
                    FfiConverterString.INSTANCE.Read(stream));
            case 12:
                return new SeyfrException.InvalidPath(
                    FfiConverterString.INSTANCE.Read(stream));
            default:
                throw new InternalException(String.Format("invalid error value '{0}' in FfiConverterTypeSeyfrError.Read()", value));
        }
    }

    public override int AllocationSize(SeyfrException value) {
        switch (value) {

            case SeyfrException.Io variant_value:
                return 4
                    + FfiConverterString.INSTANCE.AllocationSize(variant_value.@details);

            case SeyfrException.InvalidTicket variant_value:
                return 4
                    + FfiConverterString.INSTANCE.AllocationSize(variant_value.@details);

            case SeyfrException.Network variant_value:
                return 4
                    + FfiConverterString.INSTANCE.AllocationSize(variant_value.@details);

            case SeyfrException.Store variant_value:
                return 4
                    + FfiConverterString.INSTANCE.AllocationSize(variant_value.@details);

            case SeyfrException.Cancelled variant_value:
                return 4;

            case SeyfrException.FileNotFound variant_value:
                return 4
                    + FfiConverterString.INSTANCE.AllocationSize(variant_value.@path);

            case SeyfrException.NotADirectory variant_value:
                return 4
                    + FfiConverterString.INSTANCE.AllocationSize(variant_value.@path);

            case SeyfrException.EmptyFolder variant_value:
                return 4
                    + FfiConverterString.INSTANCE.AllocationSize(variant_value.@path);

            case SeyfrException.Timeout variant_value:
                return 4;

            case SeyfrException.Internal variant_value:
                return 4
                    + FfiConverterString.INSTANCE.AllocationSize(variant_value.@details);

            case SeyfrException.PathTraversal variant_value:
                return 4
                    + FfiConverterString.INSTANCE.AllocationSize(variant_value.@path)
                    + FfiConverterString.INSTANCE.AllocationSize(variant_value.@details);

            case SeyfrException.InvalidPath variant_value:
                return 4
                    + FfiConverterString.INSTANCE.AllocationSize(variant_value.@details);
            default:
                throw new InternalException(String.Format("invalid error value '{0}' in FfiConverterTypeSeyfrError.AllocationSize()", value));
        }
    }

    public override void Write(SeyfrException value, BigEndianStream stream) {
        switch (value) {
            case SeyfrException.Io variant_value:
                stream.WriteInt(1);
                FfiConverterString.INSTANCE.Write(variant_value.@details, stream);
                break;
            case SeyfrException.InvalidTicket variant_value:
                stream.WriteInt(2);
                FfiConverterString.INSTANCE.Write(variant_value.@details, stream);
                break;
            case SeyfrException.Network variant_value:
                stream.WriteInt(3);
                FfiConverterString.INSTANCE.Write(variant_value.@details, stream);
                break;
            case SeyfrException.Store variant_value:
                stream.WriteInt(4);
                FfiConverterString.INSTANCE.Write(variant_value.@details, stream);
                break;
            case SeyfrException.Cancelled variant_value:
                stream.WriteInt(5);
                break;
            case SeyfrException.FileNotFound variant_value:
                stream.WriteInt(6);
                FfiConverterString.INSTANCE.Write(variant_value.@path, stream);
                break;
            case SeyfrException.NotADirectory variant_value:
                stream.WriteInt(7);
                FfiConverterString.INSTANCE.Write(variant_value.@path, stream);
                break;
            case SeyfrException.EmptyFolder variant_value:
                stream.WriteInt(8);
                FfiConverterString.INSTANCE.Write(variant_value.@path, stream);
                break;
            case SeyfrException.Timeout variant_value:
                stream.WriteInt(9);
                break;
            case SeyfrException.Internal variant_value:
                stream.WriteInt(10);
                FfiConverterString.INSTANCE.Write(variant_value.@details, stream);
                break;
            case SeyfrException.PathTraversal variant_value:
                stream.WriteInt(11);
                FfiConverterString.INSTANCE.Write(variant_value.@path, stream);
                FfiConverterString.INSTANCE.Write(variant_value.@details, stream);
                break;
            case SeyfrException.InvalidPath variant_value:
                stream.WriteInt(12);
                FfiConverterString.INSTANCE.Write(variant_value.@details, stream);
                break;
            default:
                throw new InternalException(String.Format("invalid error value '{0}' in FfiConverterTypeSeyfrError.Write()", value));
        }
    }
}



/// <summary>
/// Progress callback.
///
/// The UI receives:
/// - `current_bytes` / `total_bytes` for the overall transfer
/// - `current_file` name for the file currently in flight
/// - `file_index` / `total_files` when transferring folders
/// </summary>
internal interface ProgressSink {
    /// <summary>
    /// Called when a new file starts processing.
    /// </summary>
    void OnFileStart(string @fileName, ulong @fileIndex, ulong @totalFiles);
    /// <summary>
    /// Called with byte-level progress for the current file.
    /// </summary>
    void OnFileProgress(string @fileName, ulong @currentBytes, ulong @totalBytes);
    /// <summary>
    /// Called when a file completes.
    /// </summary>
    void OnFileComplete(string @fileName, ulong @fileIndex, ulong @totalFiles);
    /// <summary>
    /// Called when the entire transfer completes.
    /// </summary>
    void OnComplete(string @details);
    /// <summary>
    /// Called on any error with a human-readable message.
    /// </summary>
    void OnError(string @details);
}

class UniffiCallbackInterfaceProgressSink {
    static void OnFileStart(ulong @uniffiHandle,RustBuffer @fileName,ulong @fileIndex,ulong @totalFiles,IntPtr @uniffiOutReturn,ref UniffiRustCallStatus _uniffi_out_err) {
        var handle = @uniffiHandle;
        try {
            if (!FfiConverterTypeProgressSink.INSTANCE.handleMap.TryGet(handle, out var uniffiObject)) {
                throw new InternalException($"No callback in handlemap '{handle}'");
            }
            uniffiObject.OnFileStart(
                FfiConverterString.INSTANCE.Lift(@fileName), 
                FfiConverterUInt64.INSTANCE.Lift(@fileIndex), 
                FfiConverterUInt64.INSTANCE.Lift(@totalFiles));

            _uniffi_out_err.code = UniffiCallbackResponseStatus.SUCCESS;
        }
        catch (System.Exception e){
            _uniffi_out_err.code = UniffiCallbackResponseStatus.UNEXPECTED_ERROR;
            try {
                _uniffi_out_err.error_buf = FfiConverterString.INSTANCE.Lower(e.Message);
            }
            catch {
            }
