// The ffiConverter which transforms the Callbacks in to Handles to pass to Rust.
class FfiConverterTypeProgressSink: FfiConverter<ProgressSink, ulong> {
    public static FfiConverterTypeProgressSink INSTANCE = new FfiConverterTypeProgressSink();

    public ConcurrentHandleMap<ProgressSink> handleMap = new ConcurrentHandleMap<ProgressSink>();

    public override ulong Lower(ProgressSink value) {
        return handleMap.Insert(value);
    }

    public override ProgressSink Lift(ulong value) {
        if (handleMap.TryGet(value, out var uniffiCallback)) {
            return uniffiCallback;
        } else {
            throw new InternalException($"No callback in handlemap '{value}'");
        }
    }

    public override ProgressSink Read(BigEndianStream stream) {
        return Lift(stream.ReadULong());
    }

    public override int AllocationSize(ProgressSink value) {
        return 8;
    }

    public override void Write(ProgressSink value, BigEndianStream stream) {
        stream.WriteULong(Lower(value));
    }
}




class FfiConverterOptionalTypeProgressSink: FfiConverterRustBuffer<ProgressSink?> {
    public static FfiConverterOptionalTypeProgressSink INSTANCE = new FfiConverterOptionalTypeProgressSink();

    public override ProgressSink? Read(BigEndianStream stream) {
        if (stream.ReadByte() == 0) {
            return null;
        }
        return FfiConverterTypeProgressSink.INSTANCE.Read(stream);
    }

    public override int AllocationSize(ProgressSink? value) {
        if (value == null) {
            return 1;
        } else {
            return 1 + FfiConverterTypeProgressSink.INSTANCE.AllocationSize((ProgressSink)value);
        }
    }

    public override void Write(ProgressSink? value, BigEndianStream stream) {
        if (value == null) {
            stream.WriteByte(0);
        } else {
            stream.WriteByte(1);
            FfiConverterTypeProgressSink.INSTANCE.Write((ProgressSink)value, stream);
        }
    }
}
